-- Sync stabilization P3: the unified web-facing task-status RPC.
--
-- change_task_status_v2 unifies the divergent task-status paths
-- (A-C13/B-C3/B-C4/E8): until now the web client changed tasks.status with a
-- direct UPDATE and enforced the done/blocked guards CLIENT-side only, while
-- the same guards lived server-side solely in the dormant bot RPC
-- commit_change_task_status (20260705193000). This RPC makes the guards
-- server-enforced for the web path too; the client's hard-block is removed and
-- becomes a soft precheck. Deltas from the dormant model:
--
--   * Optional CAS (p_expected_status): a stale expected status raises P0002
--     'task status changed'. P0002 is the CONVERGE signal — the client handles
--     it identically to 'task not found': refetch + gentle toast, never a
--     hard error.
--   * The blocked-reason comment is inserted HERE, exactly once (the client
--     stops double-inserting alongside the status write).
--   * Returns the post-update tasks row as jsonb (to_jsonb(t.*)) so callers
--     reconcile their cache without an extra refetch.
--   * P2 realtime parity: the domain-event statement triggers
--     (20260713110000) are deliberately SILENT for definer-executed writes
--     (the emitter's current_user guard sees the function owner, not
--     'authenticated'), so this SECURITY DEFINER RPC must insert its own
--     'tasks' ledger row or cross-session realtime for status changes is
--     lost. The insert is best-effort: a ledger hiccup never fails the
--     status change.
--
-- Guard parity with the dormant RPC (same messages, same errcodes — the
-- client matches on them):
--   * done requires a final acceptance photo (project_media.is_final) OR a
--     non-empty fully-completed checklist → else 22023.
--   * blocked requires a non-empty reason comment → else 22023.
--   * A no-op transition (status unchanged) returns immediately and skips the
--     guards: a done task predating final-photo enforcement must not fail its
--     own no-op. No comment, no ledger event.

create function public.change_task_status_v2(
  p_task_id uuid,
  p_new_status text,
  p_comment_body text default null,
  p_expected_status text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_task public.tasks%rowtype;
  v_has_final_photo boolean;
  v_has_checklist boolean;
  v_has_unchecked boolean;
  v_result jsonb;
begin
  if v_uid is null then
    raise exception 'must be authenticated' using errcode = '42501';
  end if;
  if p_new_status is null or p_new_status not in (
    'not_started', 'in_progress', 'done', 'blocked'
  ) then
    raise exception 'invalid task status %', coalesce(p_new_status, '<null>')
      using errcode = '22023';
  end if;

  -- Existence and permission surface as distinct signals (P0002 vs 42501),
  -- same as commit_change_task_status and every existing task RPC: the task
  -- id space is uuids, so the existence oracle risk is acceptable — keep
  -- parity rather than over-engineer a uniform error.
  select * into v_task
    from public.tasks
   where id = p_task_id
   for update;
  if not found then
    raise exception 'task not found' using errcode = 'P0002';
  end if;
  if not public.can_write_project_content(v_task.project_id) then
    raise exception 'insufficient permissions' using errcode = '42501';
  end if;

  -- Optional compare-and-set: the caller pins the status it believes the task
  -- has; a mismatch means another session moved it first. Checked BEFORE the
  -- no-op early return so a stale expectation always surfaces as the converge
  -- signal, even when the task already sits at the requested status.
  if p_expected_status is not null
     and v_task.status is distinct from p_expected_status then
    raise exception 'task status changed' using errcode = 'P0002';
  end if;

  if v_task.status = p_new_status then
    -- No-op transition: keep completed_at and skip the guards. A done task
    -- that predates final-photo enforcement must not fail its own no-op.
    -- Early return BEFORE the comment insert and the ledger insert: a no-op
    -- emits no sync event and writes no comment.
    return to_jsonb(v_task);
  end if;

  if p_new_status = 'done' then
    select exists (
      select 1 from public.project_media pm
       where pm.task_id = p_task_id and pm.is_final
    ) into v_has_final_photo;

    if not v_has_final_photo then
      select
        exists (select 1 from public.task_checklist_items c where c.task_id = p_task_id),
        exists (select 1 from public.task_checklist_items c where c.task_id = p_task_id and not c.is_done)
      into v_has_checklist, v_has_unchecked;

      if not v_has_checklist or v_has_unchecked then
        raise exception
          'task cannot be marked done without a final acceptance photo (or a fully completed checklist)'
          using errcode = '22023';
      end if;
    end if;
  end if;

  if p_new_status = 'blocked'
     and (p_comment_body is null or length(trim(p_comment_body)) = 0) then
    raise exception 'blocking a task requires a reason comment' using errcode = '22023';
  end if;

  -- The single server-side comment insert (the client no longer inserts its
  -- own copy alongside the status change).
  if p_comment_body is not null and length(trim(p_comment_body)) > 0 then
    insert into public.task_comments (task_id, author_profile_id, body)
    values (p_task_id, v_uid, trim(p_comment_body));
  end if;

  update public.tasks
     set status = p_new_status,
         completed_at = case
           when p_new_status = 'done' then now()
           when v_task.status = 'done' then null
           else completed_at
         end,
         updated_at = now()
   where id = p_task_id;

  -- P2 realtime parity: the emit_project_sync_event statement trigger is
  -- deliberately silent for definer-executed writes (its current_user guard
  -- sees the function owner, not 'authenticated'), so without this explicit
  -- insert other sessions would get NO realtime invalidation for status
  -- changes routed through this RPC. Best-effort by design: the sync signal
  -- is an optimization and a ledger hiccup must never fail the status change.
  begin
    insert into public.project_sync_events (project_id, kind, actor_profile_id)
    values (v_task.project_id, 'tasks', v_uid);
  exception when others then
    null;
  end;

  -- Return the operational post-update row so callers reconcile in place.
  select to_jsonb(t.*) into v_result
    from public.tasks t
   where t.id = p_task_id;
  return v_result;
end;
$$;

revoke all on function public.change_task_status_v2(uuid, text, text, text) from public;
grant execute on function public.change_task_status_v2(uuid, text, text, text) to authenticated;
grant execute on function public.change_task_status_v2(uuid, text, text, text) to service_role;
